from smolagents import FunctionTool

def safe_attachment_scan(file_path: str) -> str:
    # Simulated safe scan
    return 'safe' if not file_path.endswith('.exe') else 'blocked'

attachment_tool = FunctionTool(
    safe_attachment_scan,
    description="Scan attachments for safety before including"
)

draft_agent = CodeAgent(
    llm=llm,
    tools=[attachment_tool],
    instructions="Generate professional email draft. Scan attachments first."
)

def generate_draft(intent: str, context: str):
    return draft_agent.run(f"Intent: {intent}, Context: {context}")

approval_agent = CodeAgent(
    llm=llm,
    instructions="Validate: correct recipient? appropriate tone? no PII? Return {'approved': true/false, 'reason': str}"
)

def approve_send(draft: str, recipient: str):
    verdict = approval_agent.run({'draft': draft, 'recipient': recipient})
    if verdict.approved:
        # send_email(draft, recipient)
        return 'sent'
    return f'Rejected: {verdict.reason}'

