from vex_sdk import Policy, verify

email_policy = Policy(
    name='email_safety',
    rules=[
        {'type': 'pii_filter', 'patterns': ['SSN', 'email', 'phone']},
        {'type': 'sentiment', 'min_score': 0.7, 'categories': ['professional']},
        {'type': 'regex', 'block': ['confidential', 'internal_use_only']}
    ]
)

@verify(policies=[email_policy])
def verified_draft_generation(context):
    return draft_agent.run(context)

safe_draft = verified_draft_generation(email_context)

confidentiality_policy = Policy(
    name='recipient_validation',
    rules=[
        {'type': 'domain_check', 'allowed': ['company.com', 'partner.org']},
        {'type': 'content_classifier', 'block_classes': ['confidential', 'internal']},
        {'type': 'recipient_verify', 'require': 'valid_email_format'}
    ]
)

@verify(policies=[confidentiality_policy])
def safe_send_approval(draft, recipient):
